parameters.jsCode:
const body = $json.body || $json;
const email = String(body.email || '').toLowerCase();
const message = String(body.message || '');
const service = String(body.service || '');
const budget = String(body.project_budget || '');
const spend = String(body.monthly_spend || '');
const timeline = String(body.timeline || '');
let score = 0;
if (email && !/(gmail|hotmail|outlook|yahoo|icloud)\./.test(email)) score += 25;
if (body.company) score += 15;
if (message.length >= 80) score += 15;
if (['finops','cloud','devops','openclaw','audit'].includes(service)) score += 20;
if (['10k-plus'].includes(budget)) score += 35;
if (['5k-10k'].includes(budget)) score += 20;
if (['10k-50k','50k-plus'].includes(spend)) score += 30;
if (['5k-10k'].includes(spend)) score += 15;
if (['immediately','30-days'].includes(timeline)) score += 25;
const status = score >= 70 ? 'HOT' : score >= 40 ? 'WARM' : 'COLD';
return [{
  json: {
    timestamp: new Date().toISOString(),
    name: body.name || '',
    email,
    company: body.company || '',
    cloud_provider: body.cloud_provider || '',
    monthly_spend: spend,
    project_budget: budget,
    timeline,
    service,
    message,
    lead_source: body.lead_source || 'up2cloud.io',
    offer: body.offer || 'Free Cloud Cost and AI Efficiency Audit',
    score,
    status
  }
}];

